        tileLen_ = tileLen;
        margin_ = margin;
        d_ = d;
        anchorGm_.SetGlobalBuffer((__gm__ float*)anchor);
        positiveGm_.SetGlobalBuffer((__gm__ float*)positive);
        negativeGm_.SetGlobalBuffer((__gm__ float*)negative);
