        uint32_t blockNum = GetBlockNum();
        uint32_t blockIdx = GetBlockIdx();
        // Only block 0 does work if blockDim=1. Use grid-stride.
        // For simplicity, we process all pairs in block0.
        if (blockIdx != 0) return;
